const ReviewSubmissionSheet = forwardRef<
  BottomSheetModal,
  {
    onSubmit: (rating: number, comment: string) => void;
    initialRating?: number;
  }
>((props, ref) => {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.language === "ar";
  const [userRating, setUserRating] = useState(props.initialRating || 0);
  const [comment, setComment] = useState("");

  // Update rating if prop changes (when opening sheet)
  React.useEffect(() => {
    if (props.initialRating) {
      setUserRating(props.initialRating);
    }
  }, [props.initialRating]);

  const snapPoints = useMemo(() => [normalize(520)], []);

  const renderBackdrop = useCallback(
    (props: any) => (
      <BottomSheetBackdrop
        {...props}
        disappearsOnIndex={-1}
        appearsOnIndex={0}
        opacity={0.5}
      />
    ),
    [],
  );

  return (
    <BottomSheetModal
      ref={ref}
      index={0}
      snapPoints={snapPoints}
      backdropComponent={renderBackdrop}
      backgroundStyle={styles.sheetBackground}
      handleIndicatorStyle={styles.indicator}
      keyboardBehavior="interactive"
      keyboardBlurBehavior="restore"
      enablePanDownToClose={true}
    >
      <BottomSheetView style={styles.contentContainer}>
        {/* Wavy Background Wrapper */}
        <View style={styles.scallopedCard}>
          <Svg
            width={SCREEN_WIDTH + 80}
            height={normalize(372)}
            viewBox="0 0 500 337"
            fill="none"
            style={styles.svgBg}
            pointerEvents="none"
          >
            <Path d={SCALLOPED_BG_PATH} fill="#15AB64" />
            <Path d={TOP_SCALLOP_PATH} fill="#15AB64" />
          </Svg>

          {/* Internal UI */}
          <View style={styles.cardContent}>
            {/* Rating Stars Pill - matching footer design */}
            <View style={styles.questionPill}>
              <ThemedText style={styles.questionTitle}>
                {t("profile.review.question")}
              </ThemedText>
              <View style={styles.starsRow}>
                {[1, 2, 3, 4, 5].map((i) => (
                  <TouchableOpacity key={i} onPress={() => setUserRating(i)}>
                    {i <= userRating ? (
                      <SolarStarBold size={normalize(32)} color="#15AB64" />
                    ) : (
                      <SolarStarLinear size={normalize(32)} color="#15AB64" />
                    )}
                  </TouchableOpacity>
                ))}
              </View>
            </View>

            {/* Comments Input Area */}
            <View style={styles.inputArea}>
              <BottomSheetTextInput
                placeholder={t("profile.review.placeholder")}
                placeholderTextColor="#9CA3AF"
                multiline
                style={[
                  styles.textInput,
                  { textAlign: isRTL ? "right" : "left" },
                ]}
                value={comment}
                onChangeText={setComment}
              />
            </View>
          </View>
        </View>

        {/* Bottom Extension */}
        <View style={styles.bottomExtension}>
          <View
            style={[
              styles.actionsRow,
              { flexDirection: isRTL ? "row-reverse" : "row" },
            ]}
          >
            <SecondaryButton
              label={t("profile.review.cancel")}
              onPress={() => (ref as any).current?.dismiss()}
              isActive={false}
              style={{ flex: 1 }}
            />
            <SecondaryButton
              label={t("profile.review.send")}
              onPress={() => {
                props.onSubmit(userRating, comment);
                (ref as any).current?.dismiss();
              }}
              isActive={true}
              style={{ flex: 1 }}
              variant="inverse"
            />
          </View>
        </View>
      </BottomSheetView>
    </BottomSheetModal>
  );
});

export { ReviewSubmissionSheet };

